+/*
+ * asx/codec/codec.h — codec abstraction and canonical fixture IO
+ *
+ * JSON is the bring-up baseline. BIN is present as an explicit surface
+ * but may return unsupported until implemented.
+ *
+ * SPDX-License-Identifier: MIT
+ */
+
+#ifndef ASX_CODEC_CODEC_H
+#define ASX_CODEC_CODEC_H
+
+#include <stddef.h>
+#include <asx/asx_export.h>
+#include <asx/codec/schema.h>
+
+#ifdef __cplusplus
+extern "C" {
+#endif
+
+typedef struct {
+    char *data;
+    size_t len;
+    size_t cap;
+} asx_codec_buffer;
+
+typedef struct asx_codec_vtable {
+    asx_codec_kind codec;
+    asx_status (*encode_fixture)(const asx_canonical_fixture *fixture,
+                                 asx_codec_buffer *out_json);
+    asx_status (*decode_fixture)(const char *json,
+                                 asx_canonical_fixture *out_fixture);
+} asx_codec_vtable;
+
+/* Buffer lifecycle helpers */
+ASX_API void asx_codec_buffer_init(asx_codec_buffer *buf);
+ASX_API void asx_codec_buffer_reset(asx_codec_buffer *buf);
+
+/* Codec dispatch table lookup */
+ASX_API ASX_MUST_USE const asx_codec_vtable *asx_codec_vtable_for(asx_codec_kind codec);
+
+/* Generic wrappers that dispatch via codec vtable */
+ASX_API ASX_MUST_USE asx_status asx_codec_encode_fixture(asx_codec_kind codec,
+                                                         const asx_canonical_fixture *fixture,
+                                                         asx_codec_buffer *out_payload);
+ASX_API ASX_MUST_USE asx_status asx_codec_decode_fixture(asx_codec_kind codec,
+                                                         const char *payload,
+                                                         asx_canonical_fixture *out_fixture);
+
+/* JSON baseline helpers (codec vtable backing functions) */
+ASX_API ASX_MUST_USE asx_status asx_codec_encode_fixture_json(const asx_canonical_fixture *fixture,
+                                                              asx_codec_buffer *out_json);
+ASX_API ASX_MUST_USE asx_status asx_codec_decode_fixture_json(const char *json,
+                                                              asx_canonical_fixture *out_fixture);
+
+/* Build deterministic replay key from canonical semantic fields. */
+ASX_API ASX_MUST_USE asx_status asx_codec_fixture_replay_key(const asx_canonical_fixture *fixture,
+                                                             asx_codec_buffer *out_key);
+
+#ifdef __cplusplus
+}
+#endif
+
+#endif /* ASX_CODEC_CODEC_H */

@@ -0,0 +1,69 @@
+/*
+ * asx/codec/schema.h — canonical fixture schema model for codec surfaces
+ *
+ * Provides an in-memory representation of canonical fixture payloads
+ * consumed by JSON/BIN codec implementations.
+ *
+ * SPDX-License-Identifier: MIT
+ */
+
+#ifndef ASX_CODEC_SCHEMA_H
+#define ASX_CODEC_SCHEMA_H
+
+#include <stdint.h>
+#include <asx/asx_export.h>
+#include <asx/asx_status.h>
+
+#ifdef __cplusplus
+extern "C" {
+#endif
+
+typedef enum {
+    ASX_CODEC_KIND_JSON = 0,
+    ASX_CODEC_KIND_BIN  = 1
+} asx_codec_kind;
+
+typedef struct {
+    char *rust_baseline_commit;
+    char *rust_toolchain_commit_hash;
+    char *rust_toolchain_release;
+    char *rust_toolchain_host;
+    char *cargo_lock_sha256;
+    char *capture_run_id;
+} asx_fixture_provenance;
+
+typedef struct {
+    char *scenario_id;
+    char *fixture_schema_version;
+    char *scenario_dsl_version;
+    char *profile;
+    asx_codec_kind codec;
+    uint64_t seed;
+    char *input_json;
+    char *expected_events_json;
+    char *expected_final_snapshot_json;
+    char *expected_error_codes_json;
+    char *semantic_digest;
+    asx_fixture_provenance provenance;
+} asx_canonical_fixture;
+
+/* Initialize fixture fields to zero/empty defaults. */
+ASX_API void asx_canonical_fixture_init(asx_canonical_fixture *fixture);
+
+/* Free owned fixture strings and reset to defaults. */
+ASX_API void asx_canonical_fixture_reset(asx_canonical_fixture *fixture);
+
+/* Validate required canonical schema fields and deterministic constraints. */
+ASX_API ASX_MUST_USE asx_status asx_canonical_fixture_validate(const asx_canonical_fixture *fixture);
+
+/* Map enum to canonical codec string ("json" / "bin"). */
+ASX_API ASX_MUST_USE const char *asx_codec_kind_str(asx_codec_kind codec);
+
+/* Parse canonical codec string into enum representation. */
+ASX_API ASX_MUST_USE asx_status asx_codec_kind_parse(const char *text, asx_codec_kind *out_codec);
+
+#ifdef __cplusplus
+}
+#endif
+
+#endif /* ASX_CODEC_SCHEMA_H */
